import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSFixedServlet extends HttpServlet {

    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Proper validation and encoding to prevent XSS
        String safeUserInput = encodeHtml(userInput);

        String output = "<html><body>User input: " + safeUserInput + "</body></html>";

        response.setContentType("text/html");
        PrintWriter out = response.getWriter();
        out.println(output);
    }

    private String encodeHtml(String input) {
        return input != null ? input.replaceAll("&", "&amp;")
                                  .replaceAll("<", "&lt;")
                                  .replaceAll(">", "&gt;")
                                  .replaceAll("\"", "&quot;")
                                  .replaceAll("'", "&#39;") : "";
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
